import React from 'react';
import { Outlet } from 'react-router-dom';
import { ErpAppLayout } from '@linm-soft-org/linm-web-common-components';
import { ReduxToastContainer } from '@linm-soft-org/linm-web-common-components';
import '@linm-soft-org/linm-web-common-components/styles/variables.css';
import { isStandalone } from '../../../dev/isStandalone';
import { useInAppNavigate } from '../../../router/useInAppNavigate';
import { useListFilterSessionGuard } from '../../../hooks/useListFilterSessionGuard';
import { WorkspaceTabBar, WorkspaceTabProvider } from '../../../workspace';
import '../../../styles/reportPrint.css';

function isShellWorkspaceTabHost(): boolean {
  return typeof window !== 'undefined' && window.__LINM_SHELL_WORKSPACE_TABS__ === true;
}

export const AppLayout: React.FC = () => {
  useListFilterSessionGuard();
  const navigate = useInAppNavigate();
  const shellWorkspaceTabs = isShellWorkspaceTabHost();

  const layoutBody = (
    <ErpAppLayout
      variant="fixed"
      standalone={isStandalone}
      standaloneMode="flex-fill"
      workspaceTabBar={!shellWorkspaceTabs ? <WorkspaceTabBar /> : null}
    >
      <>
        <Outlet />
        {isStandalone && <ReduxToastContainer />}
      </>
    </ErpAppLayout>
  );

  if (shellWorkspaceTabs) {
    return layoutBody;
  }

  return (
    <WorkspaceTabProvider navigate={navigate}>
      {layoutBody}
    </WorkspaceTabProvider>
  );
};

export default AppLayout;
