import { navigateToUrl } from 'single-spa';
import { isStandalone } from '../dev/isStandalone';

export type InAppNavigateFn = (
  to: string,
  options?: { replace?: boolean; state?: unknown },
) => void;

export type InAppNavigateOptions = {
  replace?: boolean;
  state?: unknown;
};

/**
 * In-app navigation — shell: `navigateToUrl` (URL bar + MemoryRouterSync);
 * standalone: `useNavigate` (MemoryRouter + replaceState).
 * Shell + router state: memory navigate + `replaceState` (avoids MemoryRouterSync wiping state).
 */
export function navigateInAppPath(
  path: string,
  navigate: InAppNavigateFn,
  options?: InAppNavigateOptions,
): void {
  const normalized = path.startsWith('/') ? path : `/${path}`;
  if (isStandalone) {
    navigate(normalized, { replace: options?.replace, state: options?.state });
    return;
  }
  if (options?.state !== undefined) {
    navigate(normalized, { replace: options?.replace ?? true, state: options.state });
    const current = window.location.pathname + window.location.search;
    if (current !== normalized) {
      window.history.replaceState(null, '', normalized);
    }
    return;
  }
  navigateToUrl(normalized);
}
