import React, { useEffect } from 'react';
import styles from './StandaloneShell.module.css';

/** Standalone dev — overflow chain parity Root + @linm/nav (no body scroll). */
export const StandaloneShell: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  useEffect(() => {
    document.documentElement.style.setProperty('--topbar-height', '72px');
    document.documentElement.style.setProperty('--topbar-slide-height', '72px');
    document.documentElement.style.setProperty('--sidebar-width', '280px');
  }, []);

  return (
    <div className={styles.root} data-standalone-shell>
      {children}
    </div>
  );
};

export default StandaloneShell;
