import {
  ktHdmhDvId,
  ktPcId,
  ktPktId,
  ktPtId,
  ktTamUngId,
} from '../router/paths';

const DOCUMENT_VIEW_PATH: Record<string, (id: string) => string> = {
  CashReceipt: ktPtId,
  CashPayment: ktPcId,
  JournalEntry: ktPktId,
  PurchaseInvoice: ktHdmhDvId,
  AdvancePayment: ktTamUngId,
};

export function resolveDocumentViewPath(
  documentType: string | null | undefined,
  documentId: string | null | undefined,
): string | null {
  if (!documentType || !documentId) return null;
  const build = DOCUMENT_VIEW_PATH[documentType];
  return build ? build(documentId) : null;
}

export function documentTypeLabel(documentType: string | null | undefined): string {
  switch (documentType) {
    case 'CashReceipt':
      return 'Phiếu thu';
    case 'CashPayment':
      return 'Phiếu chi';
    case 'JournalEntry':
      return 'Bút toán';
    case 'PurchaseInvoice':
      return 'Hóa đơn mua';
    case 'AdvancePayment':
      return 'Tạm ứng';
    default:
      return documentType ?? '—';
  }
}

const PATH_SEGMENT_TO_DOCUMENT_TYPE: Record<string, string> = {
  pt: 'CashReceipt',
  pc: 'CashPayment',
  pkt: 'JournalEntry',
  'hdmh-dv': 'PurchaseInvoice',
  'tam-ung': 'AdvancePayment',
};

/** Resolve document type from voucher view path (`/kt/pt/:id`, …). */
export function documentTypeFromViewPath(path: string): string | null {
  const base = path.split('?')[0];
  const segments = base.split('/').filter(Boolean);
  if (segments[0] !== 'kt' || segments.length < 2) return null;
  const segment = segments[1];
  return PATH_SEGMENT_TO_DOCUMENT_TYPE[segment] ?? null;
}

export function reportTabId(returnPath: string): string {
  return `report-tab:${returnPath}`;
}
